import{_ as t,o as i,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"143A. Wages Review","description":"","frontmatter":{"title":"143A. Wages Review","eba":"Mental Health Services 2024-2028","topics":["wages","preliminary","discrimination"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/classification-staffing/143A-wages-review.md","filePath":"ebas/mental-health/health-professionals/classification-staffing/143A-wages-review.md"}'),a={name:"ebas/mental-health/health-professionals/classification-staffing/143A-wages-review.md"};function r(s,e,d,h,p,g){return i(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_143a-wages-review" tabindex="-1">143A. Wages Review <a class="header-anchor" href="#_143a-wages-review" aria-label="Permalink to &quot;143A. Wages Review&quot;">​</a></h1><p><strong>143A.1</strong> Gender based undervaluation proceedings</p><p><strong>(a)</strong> Through proceedings known as the Gender-based Undervaluation – Priority Awards review (AM2024/19 – 23) the Fair Work Commission (Commission) has considered whether identified classifications in five modern awards have been the subject of gender-based undervaluation.</p><p><strong>(b)</strong> On 16 April 2024 the Commission published a Decision in the matter, which included among other things a finding that the work of health professionals covered by the Health Professionals and Support Services Award 2020 (HPSS Award) has been the subject of gender undervaluation.</p><p><strong>(c)</strong> In the Decision the Commission also provided provisional views about variations to awards that it considered would be appropriate to remedy the gender-based undervaluation. These views continue to be the subject of further proceedings at the Commission (AM2024/20).</p><p><strong>(d)</strong> Given the provisional views expressed by the Commission, it is anticipated that an outcome of the gender-based undervaluation review by the Commission will be a decision that requires HPSS Award wage rates to be increased during the life of this Agreement to remedy the gender-based undervaluation (the HPSS Award increase Decision).</p><p><strong>143A.2</strong> Wage review working group</p><p><strong>(a)</strong> The parties agree to establish a working group to review Section 3 Employees’ wage rates. Discussions are to commence within 14 days of the Commission making a final determination with respect to matter AM2024/20.</p><p><strong>(b)</strong> The working group must include representatives of HACSU and VHIA (on behalf of Employers).</p><p><strong>(c)</strong> The working group will be responsible for delivering the following outcomes:</p><p><strong>(i)</strong> Identifying the impact of the Commission’s determination on wage rates in the HPSS Award; and</p><p><strong>(ii)</strong> Identifying the impact of the Commission’s determination on the classification structures and wage rates of Section 3 Employees in this Agreement; and</p><p><strong>(iii)</strong> Identifying the extent to which the wage rates of Section 3 Employees in this Agreement would need to be adjusted to maintain relativity with the HPSS Award both at the time the Agreement commenced and the time the Decision is delivered</p><p><strong>(iv)</strong> Identifying all possible options in relation to a gender equity wage uplift for Section 3 Employees, having regard to each of the considerations at clause 143A.3; and</p><p><strong>(v)</strong> Jointly presenting a range of options as identified in clause (iv) to the Victorian Government for consideration and approval.</p><p><strong>(d)</strong> The working group will be chaired and facilitated by an independent third party agreed by the parties, or where agreement cannot be reached on the independent third party, by a person nominated by the Minister of Mental Health. The working</p><p>group will meet on a fortnightly basis to progress the outcomes listed above and agree the review will be completed within 6 months of it commencing.</p><p><strong>143A.3</strong> Working Group considerations</p><p><strong>(a)</strong> It is agreed by the parties that the working group will have regard to the following considerations when developing the joint options at 143A.2(c)(v)</p><p><strong>(i)</strong> Employee recruitment and retention</p><p><strong>(ii)</strong> Relativity with the HPSS Award at both the time the Agreement commenced and the time the HPSS Award Increase Decision was handed down</p><p><strong>(iii)</strong> Relativity within and between the classification structures for Section 3 Employees as at both the time the Agreement commenced and the time the HPSS Award Increase Decision was handed down</p><p><strong>(iv)</strong> Career progression</p><p><strong>(v)</strong> any other wage increases arising from FWC decisions</p><p><strong>(vi)</strong> Financial implications for Employers and Government.</p><p><strong>143A.4</strong> Requests for information</p><p><strong>(a)</strong> The parties agree to the sharing of relevant information that would assist the working party to progress the outcomes listed above. This information will be provided in a timely manner. Relevant information/data may include, but is not limited to, data relating to EFT and headcount of Section 3 Employees.</p><p><strong>143A.5</strong> Setting of new wage rates Approved wage rates following review</p><p><strong>(a)</strong> Subject to the Victorian Government’s final approval of one of the presented gender equity wage uplift options for Section 3 Employees following the review, the agreement will be binding on the parties to the Agreement and will apply in lieu of the current wage rates for Section 3 Employees, to the extent it is more beneficial.</p><p><strong>143A.6</strong> No diminution of entitlements</p><p><strong>(a)</strong> No Employee will experience a diminution of any entitlements they held immediately before the outcome of this review and subsequent consideration and approval of a Government approved gender equity uplift proposal.</p><p><strong>(b)</strong> Nothing in this clause 143A is intended to affect the obligations of Employers under s 206 of the FW Act. For the avoidance of doubt, should increases to the Award which exceed Agreement rates take effect before the gender equity wage uplift for section 3 is determined under this clause 143A, Employers are required to immediately ensure compliance with such increases as required under s 206 of the FW Act.</p><p><strong>143A.7</strong> Variation of agreement The parties will give consideration to formally varying the Agreement in accordance with Part 2-4 of the Act to reflect any approved gender equity uplift for Section 3 Employees which applies in accordance with 143A.5(a). For the avoidance of doubt, such a variation is not a requirement and does not otherwise affect the binding nature of the agreement described at 143A.5(a).</p><p><strong>143A.8</strong> Resolution of disputes Any dispute about this the procedures outlined in this clause, which for clarity sake does not include any government consideration or approval, may be referred by a party to the dispute to the Commission for conciliation, and, if the matter remains unresolved, arbitration.</p>',34)])])}const m=t(a,[["render",r]]);export{c as __pageData,m as default};
